/**
 * Bootstrap 5.3.0 精简版 JS - 用于新闻系统
 * 包含基础交互功能
 */

(function () {
  'use strict';

  // 工具函数
  const getSelector = element => {
    let selector = element.getAttribute('data-bs-target');
    if (!selector || selector === '#') {
      let hrefAttr = element.getAttribute('href');
      if (hrefAttr && hrefAttr !== '#') {
        selector = hrefAttr;
      }
    }
    return selector;
  };

  const getElement = selector => {
    const el = document.querySelector(selector);
    return el;
  };

  // 下拉菜单
  class Dropdown {
    constructor(element) {
      this._element = element;
      this._parent = Dropdown.getParent(this._element);
      this._menu = Dropdown.getMenu(this._parent);
      this._addEventListeners();
    }

    static getParent(element) {
      return element.parentElement;
    }

    static getMenu(parent) {
      return parent.querySelector('.dropdown-menu');
    }

    _addEventListeners() {
      this._element.addEventListener('click', (e) => {
        e.preventDefault();
        this.toggle();
      });
    }

    toggle() {
      const isShown = this._menu.classList.contains('show');
      this.hide();
      if (!isShown) {
        this.show();
      }
    }

    show() {
      this._menu.classList.add('show');
      this._parent.classList.add('show');
    }

    hide() {
      document.querySelectorAll('.dropdown-menu.show').forEach(menu => {
        menu.classList.remove('show');
        menu.parentElement.classList.remove('show');
      });
    }
  }

  // 轮播图
  class Carousel {
    constructor(element, config) {
      this._element = element;
      this._interval = null;
      this._activeElement = null;
      this._items = Array.from(this._element.querySelectorAll('.carousel-item'));
      this._config = {
        interval: config?.interval || 5000,
        ride: config?.ride || false
      };
      
      if (this._config.ride === 'carousel') {
        this.cycle();
      }
    }

    next() {
      this._slide(1);
    }

    prev() {
      this._slide(-1);
    }

    cycle() {
      if (this._interval) {
        clearInterval(this._interval);
      }
      this._interval = setInterval(() => this.next(), this._config.interval);
    }

    pause() {
      if (this._interval) {
        clearInterval(this._interval);
      }
    }

    _slide(direction) {
      const activeItem = this._element.querySelector('.carousel-item.active');
      const nextItem = direction === 1 
        ? activeItem.nextElementSibling || this._items[0]
        : activeItem.previousElementSibling || this._items[this._items.length - 1];

      if (!nextItem || nextItem === activeItem) return;

      const isSlidingNext = direction === 1;
      const orderClassName = isSlidingNext ? 'carousel-item-next' : 'carousel-item-prev';
      const directionClassName = isSlidingNext ? 'carousel-item-start' : 'carousel-item-end';

      nextItem.classList.add(orderClassName);
      nextItem.classList.add(directionClassName);

      setTimeout(() => {
        activeItem.classList.remove('active');
        nextItem.classList.remove(orderClassName, directionClassName);
        nextItem.classList.add('active');
        activeItem.classList.add(isSlidingNext ? 'carousel-item-start' : 'carousel-item-end');
        
        setTimeout(() => {
          activeItem.classList.remove(isSlidingNext ? 'carousel-item-start' : 'carousel-item-end');
        }, 600);
      }, 10);
    }
  }

  // 模态框
  class Modal {
    constructor(element, config) {
      this._element = element;
      this._config = {
        backdrop: config?.backdrop !== false,
        keyboard: config?.keyboard !== false
      };
      this._isShown = false;
      this._backdrop = null;
    }

    show(relatedTarget) {
      if (this._isShown) return;

      const showEvent = new CustomEvent('show.bs.modal', { relatedTarget });
      this._element.dispatchEvent(showEvent);

      this._isShown = true;
      this._element.style.display = 'block';
      this._element.classList.add('show');
      
      if (this._config.backdrop) {
        this._showBackdrop();
      }

      document.body.classList.add('modal-open');
      document.body.style.overflow = 'hidden';

      const shownEvent = new CustomEvent('shown.bs.modal', { relatedTarget });
      this._element.dispatchEvent(shownEvent);
    }

    hide() {
      if (!this._isShown) return;

      const hideEvent = new CustomEvent('hide.bs.modal');
      this._element.dispatchEvent(hideEvent);

      this._isShown = false;
      this._element.classList.remove('show');
      
      setTimeout(() => {
        this._element.style.display = 'none';
      }, 300);

      if (this._backdrop) {
        this._backdrop.remove();
        this._backdrop = null;
      }

      document.body.classList.remove('modal-open');
      document.body.style.overflow = '';

      const hiddenEvent = new CustomEvent('hidden.bs.modal');
      this._element.dispatchEvent(hiddenEvent);
    }

    toggle(relatedTarget) {
      return this._isShown ? this.hide() : this.show(relatedTarget);
    }

    _showBackdrop() {
      this._backdrop = document.createElement('div');
      this._backdrop.className = 'modal-backdrop fade show';
      document.body.appendChild(this._backdrop);
    }
  }

  // 警告框关闭
  class Alert {
    constructor(element) {
      this._element = element;
    }

    close() {
      const closeEvent = new CustomEvent('close.bs.alert');
      this._element.dispatchEvent(closeEvent);

      this._element.classList.remove('show');
      
      setTimeout(() => {
        if (this._element.parentNode) {
          this._element.parentNode.removeChild(this._element);
        }
        const closedEvent = new CustomEvent('closed.bs.alert');
        this._element.dispatchEvent(closedEvent);
      }, 150);
    }
  }

  // 初始化
  document.addEventListener('DOMContentLoaded', () => {
    // 初始化下拉菜单
    document.querySelectorAll('[data-bs-toggle="dropdown"]').forEach(el => {
      new Dropdown(el);
    });

    // 初始化轮播图
    document.querySelectorAll('.carousel').forEach(el => {
      const interval = el.getAttribute('data-bs-interval');
      const ride = el.getAttribute('data-bs-ride');
      new Carousel(el, {
        interval: interval ? parseInt(interval) : 5000,
        ride: ride
      });
    });

    // 初始化模态框
    document.querySelectorAll('[data-bs-toggle="modal"]').forEach(el => {
      const target = getSelector(el);
      if (target) {
        const modalEl = getElement(target);
        if (modalEl) {
          const modal = new Modal(modalEl);
          el.addEventListener('click', () => modal.toggle(el));
        }
      }
    });

    // 初始化警告框
    document.querySelectorAll('.alert').forEach(el => {
      const btnClose = el.querySelector('.btn-close');
      if (btnClose) {
        const alert = new Alert(el);
        btnClose.addEventListener('click', () => alert.close());
      }
    });

    // 轮播图控制按钮
    document.querySelectorAll('.carousel-control-prev, .carousel-control-next').forEach(control => {
      control.addEventListener('click', (e) => {
        e.preventDefault();
        const carouselEl = control.closest('.carousel');
        if (!carouselEl) return;
        
        const carousel = new Carousel(carouselEl);
        if (control.classList.contains('carousel-control-prev')) {
          carousel.prev();
        } else {
          carousel.next();
        }
      });
    });

    // 轮播图指示器
    document.querySelectorAll('.carousel-indicators [data-bs-target]').forEach(indicator => {
      indicator.addEventListener('click', (e) => {
        e.preventDefault();
        const carouselEl = indicator.closest('.carousel');
        if (!carouselEl) return;
        
        const carousel = new Carousel(carouselEl);
        const items = carousel._items;
        const activeItem = carouselEl.querySelector('.carousel-item.active');
        const currentIndex = items.indexOf(activeItem);
        const targetIndex = parseInt(indicator.getAttribute('data-bs-slide-to') || '0');
        
        const direction = targetIndex > currentIndex ? 1 : -1;
        for (let i = 0; i < Math.abs(targetIndex - currentIndex); i++) {
          carousel._slide(direction);
        }
      });
    });
  });

  // 导出全局变量
  window.bootstrap = {
    Dropdown,
    Carousel,
    Modal,
    Alert
  };
})();
